package ru.memearena.media.application;
import org.springframework.http.HttpStatus; import ru.memearena.error.*; import java.security.*; import java.util.HexFormat;
public final class ImageInspector { public static final long MAX_BYTES=10*1024*1024; private ImageInspector(){} public static void validate(String declared, byte[] bytes){ if(bytes.length==0) throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.EMPTY_FILE,"File is empty"); if(bytes.length>MAX_BYTES) throw new ApiException(HttpStatus.PAYLOAD_TOO_LARGE,ErrorCode.FILE_TOO_LARGE,"File is too large"); if(!isSupported(declared)) throw new ApiException(HttpStatus.UNSUPPORTED_MEDIA_TYPE,ErrorCode.UNSUPPORTED_MEDIA_TYPE,"Unsupported media type"); if(!matches(declared,bytes)) throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.INVALID_FILE_CONTENT,"File content does not match media type"); } public static boolean isSupported(String t){return "image/jpeg".equals(t)||"image/png".equals(t)||"image/gif".equals(t)||"image/webp".equals(t);} public static boolean matches(String t,byte[] b){return switch(t){case "image/jpeg" -> b.length>=3&&(b[0]&255)==0xff&&(b[1]&255)==0xd8&&(b[2]&255)==0xff; case "image/png" -> b.length>=8&&(b[0]&255)==0x89&&b[1]==0x50&&b[2]==0x4e&&b[3]==0x47&&b[4]==0x0d&&b[5]==0x0a&&b[6]==0x1a&&b[7]==0x0a; case "image/gif" -> b.length>=6&&(new String(b,0,6).equals("GIF87a")||new String(b,0,6).equals("GIF89a")); case "image/webp" -> b.length>=12&&new String(b,0,4).equals("RIFF")&&new String(b,8,4).equals("WEBP"); default -> false;};} public static String sha256(byte[] b){ try{return HexFormat.of().formatHex(MessageDigest.getInstance("SHA-256").digest(b));}catch(Exception e){throw new IllegalStateException(e);} } }
